const BASE_PREMIUM: Record<string, number> = {
  amulet: 60,
};

const FIRST_INSURANCE_RATE = 0.1;
const PROCESSING_FEE = 5;

const quotePremium = (step: QuoteStep): number => {
  const policyBase = step.items.reduce(
    (sum, item) => sum + BASE_PREMIUM[item.type],
    0,
  );
  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
};
